{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표 시각은 금요일 15:00 KST로 잡되, smoke 테스트가 통과해야 한다.",
        "source": "회의 원문 확인"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 package config를 확인하고, 계약(contract) 자체가 잘못된 경우에만 스크립트 검토로 간다.",
        "source": "회의 원문 확인"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 릴리스한다.",
        "result": "거절됨",
        "reason": "smoke 테스트 통과가 선행되어야 한다."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "result": "거절됨",
        "reason": "우선 package config와 계약 적합성을 확인하는 것으로 정리되었다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스",
        "status": "내부 stretch goal",
        "note": "공개 릴리스 결정은 아니며, smoke 통과 전제의 내부 목표로만 언급되었다."
      },
      {
        "item": "README 설치 절차를 목요일까지 검토",
        "status": "가능하면 검토",
        "note": "권고로만 제시되었고 담당자는 배정되지 않았다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토",
        "status": "담당자 미배정, 확정 일정 없음"
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
        "severity": "명시되지 않음"
      },
      {
        "item": "README 설치 절차가 오래되면 릴리스 노트가 사용자를 오도할 수 있다.",
        "severity": "명시되지 않음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미해결"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?",
        "status": "미해결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 smoke 테스트 결과를 확인한다.",
      "smoke 결과 이후 tarball 경로가 맞는지 확인한다.",
      "packageName 불일치가 나오면 package config부터 점검한다.",
      "README 설치 절차가 실제 내용과 맞는지 검토 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명",
      "예산",
      "보안 사고",
      "운영 장애",
      "법무 승인 요구",
      "최종 승인자",
      "확정되지 않은 마감 시각",
      "없는 담당자"
    ]
  },
  "non_invention_rules": [
    "회의에 없던 고객명은 넣지 않는다.",
    "예산 정보는 넣지 않는다.",
    "보안 사고나 운영 장애는 언급하지 않는다.",
    "법무 승인 요구를 추가하지 않는다.",
    "최종 릴리스 승인자를 추정하지 않는다.",
    "확정되지 않은 마감 시각을 임의로 만들지 않는다.",
    "담당자가 정해지지 않은 항목에 소유자를 붙이지 않는다.",
    "원문에 없는 원인, 범위, 정책, 리스크를 추론해 확정 사실처럼 쓰지 않는다."
  ]
}
